  "code": "def split_words(txt):
    # Check for whitespaces
    if any(c.isspace() for c in txt):
        return txt.split()
    # Check for commas
    elif ',' in txt:
        return txt.split(',')
    # Otherwise, count lower-case letters with odd order
    else:
        count = 0
        for c in txt:
            if c.islower():
                # ord('a') is 0, so odd order if (ord(c)-ord('a')) % 2 == 1
                if (ord(c) - ord('a')) % 2 == 1:
                    count += 1
        return count",
